func settingsFormData(cfg cortex.Config) string {
	return `{
		form: {
			default_model: '` + cfg.DefaultModel + `',
			default_max_steps: ` + strconv.Itoa(cfg.DefaultMaxSteps) + `,
			default_max_tokens: ` + strconv.Itoa(cfg.DefaultMaxTokens) + `,
			default_temperature: ` + strconv.FormatFloat(cfg.DefaultTemperature, 'f', 2, 64) + `,
			default_reasoning_loop: '` + cfg.DefaultReasoningLoop + `'
		},
		saving: false,
		saved: false,
		async saveSettings() {
			this.saving = true;
			this.saved = false;
			try {
				const resp = await fetch('/cortex/config', {
					method: 'PUT',
					headers: { 'Content-Type': 'application/json' },
					body: JSON.stringify(this.form)
				});
				if (resp.ok) {
					this.saved = true;
					setTimeout(() => { this.saved = false; }, 3000);
				} else {
					const el = document.getElementById('settings-feedback');
					el.textContent = 'Failed to save settings';
					el.className = 'text-sm mb-4 p-2 rounded bg-destructive/10 text-destructive';
					setTimeout(() => { el.className = 'hidden text-sm mb-4 p-2 rounded'; }, 3000);
				}
			} catch (e) {
				const el = document.getElementById('settings-feedback');
				el.textContent = 'Network error';
				el.className = 'text-sm mb-4 p-2 rounded bg-destructive/10 text-destructive';
				setTimeout(() => { el.className = 'hidden text-sm mb-4 p-2 rounded'; }, 3000);
			}
			this.saving = false;
		}
	}`
}

